mapper.insert:

	SELECT CONCAT(#{sbVisitLogId},LPAD((SELECT NEXTVAL(SB_VISIT_LOG_SEQ)), 10, 0))

INSERT INTO SB_VISIT_LOG(
			 SB_VISIT_LOG_ID
			,SB_USER_ID
			,TYPE
			,VISIT_IP
			,VISIT_REFER_DOMAIN
			,VISIT_REFER
			,VISIT_ORIGIN_AGENT
			,VISIT_AGENT
			,VISIT_OS
			,VISIT_DATE
			,WORK_TYPE
			,USE_YN
			,REG_ID
			,REG_DATE
)VALUES(
			 #{id}
			,#{sbUserId, jdbcType=VARCHAR}
			,#{type, jdbcType=VARCHAR}
			,#{visitIp, jdbcType=VARCHAR}
			,#{visitReferDomain, jdbcType=VARCHAR}
			,#{visitRefer, jdbcType=VARCHAR}
			,#{visitOriginAgent, jdbcType=VARCHAR}
			,#{visitAgent, jdbcType=VARCHAR}
			,#{visitOs, jdbcType=VARCHAR}
			,NOW()
			,#{workType, jdbcType=VARCHAR}
			,'Y'
			,#{regId}
			,NOW()
)
